import { ScrollArea } from '@tale-ui/react/scroll-area';

export function ScrollableList() {
  const items = ['Item 1', 'Item 2', 'Item 3', 'Item 4', 'Item 5', 'Item 6', 'Item 7', 'Item 8'];

  return (
    <ScrollArea.Root style={{ width: 300, height: 200 }}>
      <ScrollArea.Viewport>
        <ScrollArea.Content>
          <div style={{ padding: 'var(--space-s)' }}>
            {items.map((item) => (
              <div key={item} style={{ padding: 'var(--space-xs) 0' }}>{item}</div>
            ))}
          </div>
        </ScrollArea.Content>
      </ScrollArea.Viewport>
      <ScrollArea.Scrollbar orientation="vertical">
        <ScrollArea.Thumb />
      </ScrollArea.Scrollbar>
    </ScrollArea.Root>
  );
}
